package tavoai.financial.guardrails.financial_data_protection_input

# Runtime guardrail for financial data protection input validation
# Based on EU AI Act, NIST AI RMF, and APRA CPS 230
# Specific to financial industry

# Import common modules
import data.tavoai.common.input_validation
import data.tavoai.common.data.patterns

# Default deny
default allow = false

# Allow financial data protection input if all checks pass
allow if {
    # Basic validation checks
    input_validation.allow

    # Verify this is an input document
    input.content_type == "input"

    # Financial-specific input checks
    financial_data_input_checks
}

# Core financial data input checks
financial_data_input_checks if {
    # All checks must pass
    credit_card_input_check
    bank_account_input_check
    personal_finance_input_check
    jurisdiction_input_compliance_check
}

# Credit card input check
credit_card_input_check if {
    # If credit card data detected, check if handling is appropriate based on config
    contains_credit_card_data(input.content)

    # Check if configuration allows credit card data
    input.config.credit_card_data_allowed == true
} else if {
    # No credit card data detected, automatically pass
    not contains_credit_card_data(input.content)
}

# Bank account input check
bank_account_input_check if {
    # If bank account data detected, check if handling is appropriate based on config
    contains_bank_account_data(input.content)

    # Check if configuration allows bank account data
    input.config.bank_account_data_allowed == true
} else if {
    # No bank account data detected, automatically pass
    not contains_bank_account_data(input.content)
}

# Personal finance input check
personal_finance_input_check if {
    # If personal finance data detected, ensure appropriate handling
    contains_personal_finance_data(input.content)

    # Check if configuration allows personal finance data
    input.config.personal_finance_data_allowed == true
} else if {
    # No personal finance data detected, automatically pass
    not contains_personal_finance_data(input.content)
}

# Jurisdiction-specific input compliance check
jurisdiction_input_compliance_check if {
    # Detect jurisdiction and apply appropriate checks
    jurisdiction := lower(input.metadata.jurisdiction)

    # US-specific (including GLBA and other US regulations)
    jurisdiction == "us"
    us_input_compliance_check(input.content)
} else if {
    jurisdiction := lower(input.metadata.jurisdiction)
    # EU-specific (including GDPR)
    jurisdiction == "eu"
    eu_input_compliance_check(input.content)
} else if {
    jurisdiction := lower(input.metadata.jurisdiction)
    # Australia specific
    jurisdiction == "australia" 
    australia_input_compliance_check(input.content)
} else if {
    # Default international standards for other jurisdictions
    international_input_compliance_check(input.content)
}

# Helper functions to detect financial data types
contains_credit_card_data(text) if {
    regex.match(`\b(?:\d[ -]*?){13,16}\b`, text)
}

contains_credit_card_data(text) if {
    regex.match(`(?i)credit card|card number|cvv|expiration date`, text)
}

contains_bank_account_data(text) if {
    regex.match(`\b[0-9]{8,17}\b`, text) # Account numbers
}

contains_bank_account_data(text) if {
    regex.match(`\b[0-9]{9}\b`, text) # Routing numbers
}

contains_bank_account_data(text) if {
    regex.match(`(?i)account number|routing number|bank account`, text)
}

contains_personal_finance_data(text) if {
    regex.match(`(?i)salary|income|net worth|credit score|debt|loan|mortgage`, text)
}

# Jurisdiction-specific compliance functions for input
us_input_compliance_check(text) if {
    # Check if contains restricted financial PII
    contains_financial_pii(text)

    # Ensure appropriate consent is obtained
    input.config.financial_pii_consent_obtained == true
}

us_input_compliance_check(text) if {
    # No financial PII detected
    not contains_financial_pii(text)
}

eu_input_compliance_check(text) if {
    # GDPR-specific checks
    contains_financial_pii(text)

    # Must have explicit consent for data processing
    input.config.gdpr_explicit_consent == true
}

eu_input_compliance_check(text) if {
    # No financial PII detected
    not contains_financial_pii(text)
}

australia_input_compliance_check(text) if {
    # Australia-specific checks
    true
}

international_input_compliance_check(text) if {
    # Default international standards
    true
}

# Helper function to detect financial PII
contains_financial_pii(text) if {
    contains_credit_card_data(text)
}

contains_financial_pii(text) if {
    contains_bank_account_data(text)
}

contains_financial_pii(text) if {
    regex.match(`(?i)tax.{1,20}(id|identification|number)`, text)
}

# Rejection reasons
rejection_reasons = reasons if {
    reasons := array.concat(
        input_validation_rejection_reasons,
        array.concat(
            document_type_reasons,
            financial_data_input_rejection_reasons
        )
    )
}

# Input validation rejection reasons
input_validation_rejection_reasons = reasons if {
    not input_validation.allow
    reasons := input_validation.rejection_reasons
} else = [] if {
    true
}

document_type_reasons = reasons if {
    not input.content_type == "input"
    reasons := [{"category": "Content Type", "reason": "Expected input document but received another type"}]
} else = [] if {
    true
}

# Financial data input specific rejection reasons
financial_data_input_rejection_reasons = array.concat(
    credit_card_input_reasons,
    array.concat(
        bank_account_input_reasons,
        array.concat(
            personal_finance_input_reasons,
            jurisdiction_input_reasons
        )
    )
)

# Credit card input rejection reasons
credit_card_input_reasons = reasons if {
    contains_credit_card_data(input.content)
    not input.config.credit_card_data_allowed == true
    reasons := [{"category": "Financial Data Protection", "reason": "Credit card information not allowed in input based on configuration"}]
} else = [] if {
    true
}

# Bank account input rejection reasons
bank_account_input_reasons = reasons if {
    contains_bank_account_data(input.content)
    not input.config.bank_account_data_allowed == true
    reasons := [{"category": "Financial Data Protection", "reason": "Bank account information not allowed in input based on configuration"}]
} else = [] if {
    true
}

# Personal finance input rejection reasons
personal_finance_input_reasons = reasons if {
    contains_personal_finance_data(input.content)
    not input.config.personal_finance_data_allowed == true
    reasons := [{"category": "Financial Data Protection", "reason": "Personal financial information not allowed in input based on configuration"}]
} else = [] if {
    true
}

# Jurisdiction-specific input rejection reasons
jurisdiction_input_reasons = array.concat(us_input_reasons, eu_input_reasons)

us_input_reasons = reasons if {
    jurisdiction := lower(input.metadata.jurisdiction)
    jurisdiction == "us"
    contains_financial_pii(input.content)
    not input.config.financial_pii_consent_obtained == true
    reasons := [{"category": "Financial Data Protection", "reason": "Financial PII detected in US context without proper consent (GLBA violation)"}]
} else = [] if {
    true
}

eu_input_reasons = reasons if {
    jurisdiction := lower(input.metadata.jurisdiction)
    jurisdiction == "eu"
    contains_financial_pii(input.content)
    not input.config.gdpr_explicit_consent == true
    reasons := [{"category": "Financial Data Protection", "reason": "Financial PII detected in EU context without explicit GDPR consent"}]
} else = [] if {
    true
}

# Policy Metadata
policy_metadata = {
    "name": "Financial Data Protection Input Guardrail",
    "description": "Content-based runtime guardrail for protecting sensitive financial data in inputs to GenAI applications",
    "version": "1.1.0",
    "last_updated": "2023-07-15",
    "regulatory_references": [
        "EU AI Act",
        "NIST AI RMF",
        "APRA CPS 230",
        "PCI DSS",
        "GLBA",
        "GDPR",
        "CCPA"
    ]
}

package tavoai.financial.guardrails.financial_data_protection_output

# Runtime guardrail for financial data protection output validation
# Based on EU AI Act, NIST AI RMF, and APRA CPS 230
# Specific to financial industry

# Import common modules
import data.tavoai.common.output_filtering
import data.tavoai.common.data.patterns

# Default deny
default allow = false

# Allow financial data protection output if all checks pass
allow if {
    # Basic output filtering checks
    output_filtering.allow

    # Verify this is an output document
    input.content_type == "output"

    # Financial-specific output checks
    financial_data_output_checks
}

# Core financial data output checks
financial_data_output_checks if {
    # All checks must pass
    credit_card_output_check
    bank_account_output_check
    personal_finance_output_check
    transaction_data_protection_check
    jurisdiction_output_compliance_check
}

# Credit card output check
credit_card_output_check if {
    # Check if output properly handles credit card data
    credit_card_properly_handled(input.content)
}

# Bank account output check
bank_account_output_check if {
    # Check if output properly handles bank account data
    bank_account_properly_handled(input.content)
}

# Personal finance output check
personal_finance_output_check if {
    # Check if output properly handles personal finance data
    personal_finance_properly_handled(input.content)
}

# Transaction data protection check
transaction_data_protection_check if {
    # If use case is transaction related, verify proper protections
    is_transaction_related(input.metadata.use_case)
    transaction_data_properly_handled(input.content)
} else if {
    # Not transaction-related use case, auto-pass
    not is_transaction_related(input.metadata.use_case)
}

# Jurisdiction-specific output compliance check
jurisdiction_output_compliance_check if {
    # Detect jurisdiction and apply appropriate checks
    jurisdiction := lower(input.metadata.jurisdiction)

    # US-specific (including GLBA and other US regulations)
    jurisdiction == "us"
    us_output_compliance_check(input.content)
} else if {
    jurisdiction := lower(input.metadata.jurisdiction)
    # EU-specific (including GDPR)
    jurisdiction == "eu"
    eu_output_compliance_check(input.content)
} else if {
    jurisdiction := lower(input.metadata.jurisdiction)
    # Australia specific
    jurisdiction == "australia" 
    australia_output_compliance_check(input.content)
} else if {
    # Default international standards for other jurisdictions
    international_output_compliance_check(input.content)
}

# Helper functions to detect financial data types
contains_credit_card_data(text) if {
    regex.match(`\b(?:\d[ -]*?){13,16}\b`, text)
}

contains_bank_account_data(text) if {
    regex.match(`\b[0-9]{8,17}\b`, text) # Account numbers
}

contains_bank_account_data(text) if {
    regex.match(`\b[0-9]{9}\b`, text) # Routing numbers
}

# Helper functions to check proper handling in output
credit_card_properly_handled(text) if {
    # Only the last 4 digits should be visible
    not regex.match(`\b(?:\d[ -]*?){13,16}\b`, text)

    # Should use a masked format like XXXX-XXXX-XXXX-1234
    regex.match(`(?i)card ending|ending in \d{4}|account ending|last 4|xxxx|[*]+\d{4}`, text)
} else if {
    # If no credit card data is present, automatically pass
    not regex.match(`(?i)credit card|card number|cvv|expiration date`, text)
}

bank_account_properly_handled(text) if {
    # No full account numbers
    not regex.match(`\b[0-9]{8,17}\b`, text)

    # No full routing numbers
    not regex.match(`\b[0-9]{9}\b`, text)

    # Should use masked format or last digits only
    regex.match(`(?i)account ending|ending in \d{4}|last 4|xxxx|[*]+\d{4}`, text)
} else if {
    # If no bank account data is present, automatically pass
    not regex.match(`(?i)account number|routing number|bank account`, text)
}

personal_finance_properly_handled(text) if {
    # Should not include specific amounts for personal finance data
    not regex.match(`\$\d+,\d+|\$\d+\.\d+`, text)
} else if {
    # If no personal finance data is present, automatically pass
    not regex.match(`(?i)salary|income|net worth|credit score|debt|loan|mortgage`, text)
}

transaction_data_properly_handled(text) if {
    # Should not include precise transaction amounts
    not regex.match(`\$\d+,\d+\.\d+`, text)

    # Should not include precise timestamps
    not regex.match(`\d{2}:\d{2}:\d{2}`, text)

    # Should not include precise locations
    not regex.match(`(?i)at \d+ [a-z]+ street|avenue|boulevard`, text)
}

# Jurisdiction-specific compliance functions
us_output_compliance_check(text) if {
    # Check if contains PCI regulated data
    contains_credit_card_data(text)

    # No CVV in output (prohibited by PCI)
    not regex.match(`(?i)cvv|cvc|security code|3 digit|4 digit`, text)
} else if {
    # If no credit card data, pass
    not contains_credit_card_data(text)
}

eu_output_compliance_check(text) if {
    # GDPR requires strong data minimization
    not regex.match(`\b(?:\d[ -]*?){13,16}\b`, text)
    not regex.match(`\b[0-9]{8,17}\b`, text)
    not regex.match(`\b[0-9]{9}\b`, text)
}

australia_output_compliance_check(text) if {
    # Similar to EU but with Australia-specific requirements
    not regex.match(`\b(?:\d[ -]*?){13,16}\b`, text)
    not regex.match(`\b[0-9]{8,17}\b`, text)
}

international_output_compliance_check(text) if {
    # Default to strictest regulations for international use
    not regex.match(`\b(?:\d[ -]*?){13,16}\b`, text)
    not regex.match(`\b[0-9]{8,17}\b`, text)
    not regex.match(`\b[0-9]{9}\b`, text)
}

# Helper function to identify transaction-related use cases
is_transaction_related(use_case) if {
    transaction_use_cases := [
        "payment_processing",
        "transaction_history",
        "fund_transfer",
        "purchase",
        "checkout"
    ]

    some i
    transaction_use_cases[i] == use_case
}

# Rejection reasons
rejection_reasons = reasons if {
    reasons := array.concat(
        output_filtering_rejection_reasons,
        array.concat(
            document_type_reasons,
            array.concat(
                credit_card_output_reasons,
                array.concat(
                    bank_account_output_reasons,
                    array.concat(
                        personal_finance_output_reasons,
                        array.concat(
                            transaction_output_reasons,
                            jurisdiction_output_reasons
                        )
                    )
                )
            )
        )
    )
}

# Output filtering rejection reasons
output_filtering_rejection_reasons = reasons if {
    not output_filtering.allow
    reasons := output_filtering.rejection_reasons
} else = [] if {
    true
}

document_type_reasons = reasons if {
    not input.content_type == "output"
    reasons := [{"category": "Content Type", "reason": "Expected output document but received another type"}]
} else = [] if {
    true
}

# Financial-specific output rejection reasons
financial_output_rejection_reasons = array.concat(
    credit_card_output_reasons,
    array.concat(
        bank_account_output_reasons,
        array.concat(
            personal_finance_output_reasons,
            array.concat(
                transaction_output_reasons,
                jurisdiction_output_reasons
            )
        )
    )
)

# Credit card output rejection reasons
credit_card_output_reasons = reasons if {
    regex.match(`\b(?:\d[ -]*?){13,16}\b`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Credit card number not properly masked in output"}]
} else = reasons if {
    regex.match(`(?i)credit card|card number|cvv|expiration date`, input.content)
    not regex.match(`(?i)card ending|ending in \d{4}|account ending|last 4|xxxx|[*]+\d{4}`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Credit card information not properly formatted in output"}]
} else = [] if {
    true
}

# Bank account output rejection reasons
bank_account_output_reasons = reasons if {
    regex.match(`\b[0-9]{8,17}\b`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Bank account number not properly masked in output"}]
} else = reasons if {
    regex.match(`\b[0-9]{9}\b`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Routing number not properly masked in output"}]
} else = reasons if {
    regex.match(`(?i)account number|routing number|bank account`, input.content)
    not regex.match(`(?i)account ending|ending in \d{4}|last 4|xxxx|[*]+\d{4}`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Bank account information not properly formatted in output"}]
} else = [] if {
    true
}

# Personal finance output rejection reasons
personal_finance_output_reasons = reasons if {
    regex.match(`(?i)salary|income|net worth|credit score|debt|loan|mortgage`, input.content)
    regex.match(`\$\d+,\d+|\$\d+\.\d+`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Personal financial information contains specific amounts in output"}]
} else = [] if {
    true
}

# Transaction data output rejection reasons
transaction_output_reasons = reasons if {
    is_transaction_related(input.metadata.use_case)
    regex.match(`\$\d+,\d+\.\d+`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Transaction data contains precise amounts in output"}]
} else = reasons if {
    is_transaction_related(input.metadata.use_case)
    regex.match(`\d{2}:\d{2}:\d{2}`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Transaction data contains precise timestamps in output"}]
} else = reasons if {
    is_transaction_related(input.metadata.use_case)
    regex.match(`(?i)at \d+ [a-z]+ street|avenue|boulevard`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "Transaction data contains precise locations in output"}]
} else = [] if {
    true
}

# Jurisdiction-specific output rejection reasons
jurisdiction_output_reasons = reasons if {
    jurisdiction := lower(input.metadata.jurisdiction)
    jurisdiction == "us"
    contains_credit_card_data(input.content)
    regex.match(`(?i)cvv|cvc|security code|3 digit|4 digit`, input.content)
    reasons := [{"category": "Financial Data Protection", "reason": "CVV/CVC security codes must never be included in output (PCI DSS violation)"}]
} else = [] if {
    true
}

# Policy Metadata
policy_metadata = {
    "name": "Financial Data Protection Output Guardrail",
    "description": "Content-based runtime guardrail for protecting sensitive financial data in outputs from GenAI applications",
    "version": "1.1.0",
    "last_updated": "2023-07-15",
    "regulatory_references": [
        "EU AI Act",
        "NIST AI RMF",
        "APRA CPS 230",
        "PCI DSS",
        "GLBA",
        "GDPR",
        "CCPA"
    ]
}

package tavoai.financial.guardrails.financial_advice_input

# Runtime guardrail for financial advice input validation
# Based on EU AI Act, NIST AI RMF, and APRA CPS 230
# Specific to financial industry

# Import common guardrails and pattern definitions
import data.tavoai.common.input_validation
import data.tavoai.common.data.patterns

# Default deny
default allow = false

# Allow financial advice input if all checks pass
allow if {
    # Input validation
    input_validation.allow

    # Additional input-specific checks
    input.content_type == "input"  # Verify this is an input document
    financial_input_checks
}

# Additional checks specific to financial advice inputs
financial_input_checks if {
    # Check if the input is appropriate for financial advice
    not contains_prohibited_financial_requests(input.content)
}

# Helper function to detect prohibited financial requests
contains_prohibited_financial_requests(text) if {
    prohibited_patterns := [
        "(?i)guaranteed (returns|profits|income)",
        "(?i)risk-free investment",
        "(?i)get rich quick",
        "(?i)avoid (taxes|taxation)",
        "(?i)tax (evasion|avoidance)",
        "(?i)inside (information|trading)",
        "(?i)pump and dump",
        "(?i)market manipulation"
    ]

    pattern := prohibited_patterns[_]
    regex.match(pattern, text)
}

# Rejection reasons
rejection_reasons = reasons if {
    reasons := array.concat(
        input_validation_rejection_reasons,
        financial_input_rejection_reasons
    )
}

# Input validation rejection reasons
input_validation_rejection_reasons = reasons if {
    not input_validation.allow
    reasons := input_validation.rejection_reasons
} else = [] if {
    true
}

# Financial input specific rejection reasons
financial_input_rejection_reasons = reasons if {
    not input.content_type == "input"
    reasons := [{"category": "Content Type", "reason": "Expected input document but received another type"}]
} else = reasons if {
    contains_prohibited_financial_requests(input.content)
    reasons := [{"category": "Financial Input", "reason": "Input contains requests for prohibited financial advice"}]
} else = [] if {
    true
}

# Policy Metadata
policy_metadata = {
    "name": "Financial Advice Input Guardrail",
    "description": "Input validation guardrail for financial advice in GenAI applications",
    "version": "1.1.0",
    "last_updated": "2023-07-15",
    "regulatory_references": [
        "EU AI Act",
        "NIST AI RMF",
        "APRA CPS 230"
    ]
}

package tavoai.financial.guardrails.financial_advice_output

# Runtime guardrail for financial advice output validation
# Based on EU AI Act, NIST AI RMF, and APRA CPS 230
# Specific to financial industry

# Import common guardrails and pattern definitions
import data.tavoai.common.output_filtering
import data.tavoai.common.data.patterns

# Default deny
default allow = false

# Allow financial advice output if all checks pass
allow if {
    # Output filtering
    output_filtering.allow

    # Additional output-specific checks
    input.content_type == "output"  # Verify this is an output document

    # Financial advice specific checks
    advice_qualification_compliant
    advice_disclaimers_compliant
    advice_limitations_compliant
    advice_risk_disclosure_compliant
    advice_regulatory_compliant
}

# Advice qualification check
advice_qualification_compliant if {
    # Check if advice is qualified - content-based approach
    advice_type := categorize_advice(input.content)
    is_qualified_for_advice_type(advice_type, input.content)
}

# Advice disclaimers check
advice_disclaimers_compliant if {
    # Check if all required disclaimers are included
    contains_generic_financial_disclaimer(input.content)
}

# Advice limitations check
advice_limitations_compliant if {
    # Check if appropriate limitations are mentioned
    contains_advice_limitations(input.content)
}

# Risk disclosure check
advice_risk_disclosure_compliant if {
    # Check if risks are properly disclosed
    contains_risk_disclosure(input.content)
}

# Regulatory compliance check
advice_regulatory_compliant if {
    # Check jurisdiction-specific regulatory compliance
    jurisdiction := lower(input.metadata.jurisdiction)
    jurisdiction_compliant(jurisdiction, input.content)
}

# Helper function to categorize financial advice
categorize_advice(text) = advice_type if {
    contains_investment_advice(text)
    advice_type := "investment"
} else = advice_type if {
    contains_retirement_advice(text)
    advice_type := "retirement"
} else = advice_type if {
    contains_tax_advice(text)
    advice_type := "tax"
} else = advice_type if {
    contains_debt_advice(text)
    advice_type := "debt"
} else = advice_type if {
    contains_insurance_advice(text)
    advice_type := "insurance"
} else = advice_type if {
    advice_type := "general"
}

# Helper functions to identify different types of advice
contains_investment_advice(text) if {
    investment_terms := [
        "investment", "stock", "bond", "mutual fund", "etf", 
        "portfolio", "asset allocation", "diversification"
    ]
    term := investment_terms[_]
    contains(lower(text), term)
}

contains_retirement_advice(text) if {
    retirement_terms := [
        "retirement", "pension", "401k", "ira", "superannuation",
        "annuity", "social security"
    ]
    term := retirement_terms[_]
    contains(lower(text), term)
}

contains_tax_advice(text) if {
    tax_terms := [
        "tax", "deduction", "credit", "write-off", "capital gains",
        "irs", "filing", "return"
    ]
    term := tax_terms[_]
    contains(lower(text), term)
}

contains_debt_advice(text) if {
    debt_terms := [
        "debt", "loan", "mortgage", "credit card", "interest rate",
        "refinance", "consolidation", "bankruptcy"
    ]
    term := debt_terms[_]
    contains(lower(text), term)
}

contains_insurance_advice(text) if {
    insurance_terms := [
        "insurance", "policy", "premium", "coverage", "deductible",
        "claim", "underwriting", "risk management"
    ]
    term := insurance_terms[_]
    contains(lower(text), term)
}

# Check if content is qualified to provide advice
is_qualified_for_advice_type(advice_type, text) if {
    qualification_patterns := [
        "(?i)general (information|advice)",
        "(?i)not (personalized|individual) (advice|recommendation)",
        "(?i)consult.{1,30}(financial|professional) (advisor|adviser)",
        "(?i)not a substitute for professional financial advice"
    ]

    pattern := qualification_patterns[_]
    regex.match(pattern, text)
}

# Check for generic financial disclaimer
contains_generic_financial_disclaimer(text) if {
    disclaimer_patterns := [
        "(?i)past performance is not (indicative|guarantee)",
        "(?i)investment involves risk",
        "(?i)value.{1,30}(go down|decrease|fluctuate)",
        "(?i)consult.{1,30}professional financial advisor",
        "(?i)not (financial|investment|tax|professional) advice"
    ]

    pattern := disclaimer_patterns[_]
    regex.match(pattern, text)
}

# Check for advice limitations
contains_advice_limitations(text) if {
    limitation_patterns := [
        "(?i)based on (limited|general) information",
        "(?i)individual circumstances (may|will) vary",
        "(?i)depends on your (specific|personal|individual) (situation|circumstances)",
        "(?i)should consider your (objectives|needs|situation)"
    ]

    pattern := limitation_patterns[_]
    regex.match(pattern, text)
}

# Check for risk disclosure
contains_risk_disclosure(text) if {
    risk_patterns := [
        "(?i)risk (of|to) (capital|principal|investment)",
        "(?i)may (lose|result in loss|decline in value)",
        "(?i)investment involves risk",
        "(?i)no guarantee of (return|profit)",
        "(?i)value.{1,30}(go down|decrease|fluctuate)"
    ]

    pattern := risk_patterns[_]
    regex.match(pattern, text)
}

# Check jurisdiction-specific compliance
jurisdiction_compliant(jurisdiction, text) if {
    jurisdiction == "us"
    us_compliant(text)
} else if {
    jurisdiction == "eu"
    eu_compliant(text)
} else if {
    jurisdiction == "australia"
    australia_compliant(text)
} else if {
    # Default international compliance
    contains_generic_financial_disclaimer(text)
}

# US-specific compliance
us_compliant(text) if {
    contains_generic_financial_disclaimer(text)
}

# EU-specific compliance
eu_compliant(text) if {
    contains_generic_financial_disclaimer(text)
    contains_risk_disclosure(text)
}

# Australia-specific compliance
australia_compliant(text) if {
    australia_disclaimer_patterns := [
        "(?i)general advice only",
        "(?i)not taken into account your (objectives|needs|situation)",
        "(?i)financial product",
        "(?i)australian financial services"
    ]

    pattern := australia_disclaimer_patterns[_]
    regex.match(pattern, text)
}

# Rejection Reasons
rejection_reasons = reasons if {
    reasons := array.concat(
        output_filtering_rejection_reasons,
        financial_output_rejection_reasons
    )
}

# Output filtering rejection reasons
output_filtering_rejection_reasons = reasons if {
    not output_filtering.allow
    reasons := output_filtering.rejection_reasons
} else = [] if {
    true
}

# Define reasons based on compliance checks, providing default empty lists
qualification_reasons = reasons if {
    not advice_qualification_compliant
    reasons := [{"category": "Qualification", "reason": "Advice qualification requirements not met"}]
} else = [] if { true }

disclaimer_reasons = reasons if {
    not advice_disclaimers_compliant
    reasons := [{"category": "Disclaimers", "reason": "Required disclaimers are missing"}]
} else = [] if { true }

limitations_reasons = reasons if {
    not advice_limitations_compliant
    reasons := [{"category": "Limitations", "reason": "Advice limitations are not properly stated"}]
} else = [] if { true }

risk_reasons = reasons if {
    not advice_risk_disclosure_compliant
    reasons := [{"category": "Risk Disclosure", "reason": "Risk disclosures are inadequate or missing"}]
} else = [] if { true }

regulatory_reasons = reasons if {
    not advice_regulatory_compliant
    reasons := [{"category": "Regulatory", "reason": "Jurisdiction-specific regulatory requirements not met"}]
} else = [] if { true }

# Financial output specific rejection reasons
# Use array.concat to combine the reason lists, not '+'
financial_output_rejection_reasons = array.concat(
    array.concat(
        array.concat(
            array.concat(
                array.concat(document_type_reasons, qualification_reasons),
                disclaimer_reasons),
            limitations_reasons),
        risk_reasons),
    regulatory_reasons
)

document_type_reasons = reasons if {
    not input.content_type == "output"
    reasons := [{"category": "Content Type", "reason": "Expected output document but received another type"}]
} else = [] if {
    true
}

package tavoai.healthcare.guardrails.medical_information_output

# Runtime guardrail for medical information output validation
# Based on EU AI Act, NIST AI RMF, and APRA CPS 230
# Specific to healthcare industry

# Import common modules
import data.tavoai.common.output_filtering
import data.tavoai.common.data.patterns

# Default deny
default allow = false

# Allow medical information output if all checks pass
allow if {
    # Basic output validation checks
    output_filtering.allow

    # Verify this is an output document
    input.content_type == "output"

    # Healthcare-specific output checks
    medical_output_checks
}

# Core medical information output checks
medical_output_checks if {
    # Check if the output contains appropriate medical disclaimers
    contains_medical_disclaimers(input.content)

    # Check if the output mentions limitations
    contains_limitations(input.content)

    # Check if the output avoids medical misinformation
    not contains_medical_misinformation(input.content)

    # Check for jurisdiction compliance
    jurisdiction_compliance
}

# Helper function to check for medical disclaimers
contains_medical_disclaimers(text) if {
    disclaimer_patterns := [
        "(?i)not (a )?(medical|healthcare|clinical) advice",
        "(?i)consult.{1,30}(healthcare|medical) (professional|provider|doctor)",
        "(?i)not.{1,30}substitute.{1,30}(medical|healthcare|professional).{1,30}(advice|consultation|opinion)",
        "(?i)speak.{1,30}(with|to).{1,30}(healthcare|medical) (professional|provider|doctor)"
    ]

    pattern := disclaimer_patterns[_]
    regex.match(pattern, text)
}

# Helper function to check for limitations
contains_limitations(text) if {
    limitations_patterns := [
        "(?i)(information|content).{1,30}(general|educational).{1,30}(purposes|use)",
        "(?i)(cannot|not able to).{1,30}(diagnose|treat|prescribe)",
        "(?i)based.{1,30}(general|available).{1,30}information",
        "(?i)individual.{1,30}(conditions|situations|cases).{1,30}(may|might|can).{1,30}(vary|differ|be different)"
    ]

    pattern := limitations_patterns[_]
    regex.match(pattern, text)
}

# Helper function to check for medical misinformation
contains_medical_misinformation(text) if {
    misinformation_patterns := [
        "(?i)(cure|treat|heal).{1,30}(cancer|diabetes|alzheimer|hiv|aids).{1,30}(with|using|through).{1,30}(natural|alternative|home)",
        "(?i)vaccines.{1,30}(cause|linked to).{1,30}autism",
        "(?i)(covid|coronavirus).{1,30}(hoax|fake|conspiracy)",
        "(?i)5g.{1,30}(cause|spread).{1,30}(covid|coronavirus|virus|disease)"
    ]

    pattern := misinformation_patterns[_]
    regex.match(pattern, text)
}

# Jurisdiction compliance check
jurisdiction_compliance if {
    # Get jurisdiction from metadata
    jurisdiction := input.metadata.jurisdiction

    # Apply jurisdiction-specific rules
    jurisdiction_specific_compliance(jurisdiction, input.content)
}

# US-specific compliance
jurisdiction_specific_compliance("US", text) if {
    # FDA compliance - must include specific medical device disclaimers if applicable
    not contains_medical_device_references(text)
} else if {
    # If there are medical device references, must include FDA disclaimer
    contains_medical_device_references(text)
    contains_fda_disclaimer(text)
}

# EU-specific compliance
jurisdiction_specific_compliance("EU", text) if {
    # GDPR and EU medical information compliance
    not contains_treatment_recommendations(text)
} else if {
    # If there are treatment recommendations, must include EU healthcare disclaimer
    contains_treatment_recommendations(text)
    contains_eu_healthcare_disclaimer(text)
}

# Australia-specific compliance
jurisdiction_specific_compliance("Australia", text) if {
    # TGA compliance
    not contains_therapeutic_claims(text)
} else if {
    # If there are therapeutic claims, must include TGA disclaimer
    contains_therapeutic_claims(text)
    contains_tga_disclaimer(text)
}

# Default jurisdiction compliance (when not US, EU, or Australia)
jurisdiction_specific_compliance(jurisdiction, text) if {
    # Default compliance check for other jurisdictions
    true
}

# Helper functions for jurisdiction-specific compliance

# Check for medical device references
contains_medical_device_references(text) if {
    medical_device_patterns := [
        "(?i)medical device",
        "(?i)(monitor|track).{1,30}(blood pressure|glucose|heart rate)",
        "(?i)(wearable|implant).{1,30}(device|monitor|tracker)"
    ]

    pattern := medical_device_patterns[_]
    regex.match(pattern, text)
}

# Check for FDA disclaimer
contains_fda_disclaimer(text) if {
    regex.match("(?i)(FDA|Food and Drug Administration).{1,50}(not|hasn't).{1,50}(approved|evaluated|cleared)", text)
}

# Check for treatment recommendations
contains_treatment_recommendations(text) if {
    treatment_patterns := [
        "(?i)(recommend|suggest|advise).{1,30}(taking|using|try).{1,30}(medication|drug|treatment)",
        "(?i)(start|begin|initiate).{1,30}(therapy|treatment|medication)",
        "(?i)(increase|decrease|adjust).{1,30}(dose|dosage|medication)"
    ]

    pattern := treatment_patterns[_]
    regex.match(pattern, text)
}

# Check for EU healthcare disclaimer
contains_eu_healthcare_disclaimer(text) if {
    regex.match("(?i)(information|content).{1,50}(complies|accordance|aligned).{1,50}(EU|European Union).{1,50}(regulations|directives|guidelines)", text)
}

# Check for therapeutic claims
contains_therapeutic_claims(text) if {
    therapeutic_patterns := [
        "(?i)(treats|cures|alleviates|prevents).{1,30}(disease|condition|disorder)",
        "(?i)(therapeutic|medicinal|healing).{1,30}(benefits|properties|effects)",
        "(?i)clinically.{1,30}(proven|tested|shown)"
    ]

    pattern := therapeutic_patterns[_]
    regex.match(pattern, text)
}

# Check for TGA disclaimer
contains_tga_disclaimer(text) if {
    regex.match("(?i)(TGA|Therapeutic Goods Administration).{1,50}(not|hasn't).{1,50}(approved|evaluated)", text)
}

# Rejection reasons
rejection_reasons = reasons if {
    reasons := array.concat(
        output_filtering_rejection_reasons,
        array.concat(
            document_type_reasons,
            array.concat(
                disclaimer_reasons,
                array.concat(
                    limitation_reasons,
                    array.concat(
                        misinformation_reasons,
                        jurisdiction_reasons
                    )
                )
            )
        )
    )
}

# Output filtering rejection reasons
output_filtering_rejection_reasons = reasons if {
    not output_filtering.allow
    reasons := output_filtering.rejection_reasons
} else = [] if {
    true
}

# Medical output specific rejection reasons
document_type_reasons = reasons if {
    not input.content_type == "output"
    reasons := [{"category": "Content Type", "reason": "Expected output document but received another type"}]
} else = [] if {
    true
}

disclaimer_reasons = reasons if {
    not contains_medical_disclaimers(input.content)
    reasons := [{"category": "Medical Disclaimers", "reason": "Output is missing required medical disclaimers"}]
} else = [] if {
    true
}

limitation_reasons = reasons if {
    not contains_limitations(input.content)
    reasons := [{"category": "Limitations", "reason": "Output does not mention limitations of the provided information"}]
} else = [] if {
    true
}

misinformation_reasons = reasons if {
    contains_medical_misinformation(input.content)
    reasons := [{"category": "Misinformation", "reason": "Output contains potential medical misinformation"}]
} else = [] if {
    true
}

jurisdiction_reasons = reasons if {
    not jurisdiction_compliance
    reasons := [{"category": "Jurisdiction Compliance", "reason": "Output does not comply with jurisdiction-specific healthcare regulations"}]
} else = [] if {
    true
}

# Policy Metadata
policy_metadata = {
    "name": "Medical Information Output Guardrail",
    "description": "Output validation guardrail for medical information in GenAI applications",
    "version": "1.1.0",
    "last_updated": "2023-07-15",
    "regulatory_references": [
        "EU AI Act",
        "NIST AI RMF",
        "APRA CPS 230",
        "FDA Regulations",
        "HIPAA",
        "EU MDR",
        "TGA Requirements"
    ]
}

package tavoai.healthcare.guardrails.patient_data_protection_input

# Runtime guardrail for patient data protection input validation
# Based on EU AI Act, NIST AI RMF, HIPAA, GDPR and other privacy regulations
# Specific to healthcare industry

# Import common modules
import data.tavoai.common.input_validation
import data.tavoai.common.data.patterns

# Default deny
default allow = false

# Allow patient data input if all checks pass
allow if {
    # Basic validation checks
    input_validation.allow

    # Verify this is an input document
    input.content_type == "input"

    # Healthcare-specific patient data input checks
    patient_data_input_checks
}

# Core patient data input checks
patient_data_input_checks if {
    # Check if the input request is appropriate for patient data
    not contains_prohibited_patient_data_requests(input.content)

    # Check if configuration is appropriate for PHI
    phi_config_check

    # Additional checks for specific data types
    not contains_ssn_request(input.content)
    not contains_financial_info_request(input.content)

    # Ensure appropriate user authentication level for data access
    user_authentication_level_check
}

# Helper function to detect prohibited patient data requests
contains_prohibited_patient_data_requests(text) if {
    prohibited_patterns := [
        "(?i)show me (all|every|the|complete).{1,30}patient",
        "(?i)list.{1,30}(patient|medical).{1,30}record",
        "(?i)give me.{1,30}(patient|medical|health).{1,30}(data|information|details)",
        "(?i)access.{1,30}(patient|medical|health).{1,30}(data|information|details)"
    ]

    # Unless explicitly requesting de-identified or aggregated data
    not regex.match("(?i)(de-identified|anonymous|anonymized|aggregated|summary|statistics)", text)

    pattern := prohibited_patterns[_]
    regex.match(pattern, text)
}

# Helper function to detect SSN requests
contains_ssn_request(text) if {
    ssn_patterns := [
        "(?i)social security",
        "(?i)ssn",
        "(?i)tax.{1,10}(id|identification|number)",
        "(?i)government.{1,10}(id|identification|number)"
    ]

    pattern := ssn_patterns[_]
    regex.match(pattern, text)
}

# Helper function to detect financial information requests
contains_financial_info_request(text) if {
    financial_patterns := [
        "(?i)(credit|debit).{1,10}card",
        "(?i)bank.{1,10}account",
        "(?i)payment.{1,10}(details|information)",
        "(?i)billing.{1,10}(information|details)"
    ]

    pattern := financial_patterns[_]
    regex.match(pattern, text)
}

# Check if configuration is appropriate for PHI data
phi_config_check if {
    # For PHI content, PHI detection should be enabled
    input.config.phi_detection_enabled == true

    # For PHI content, HIPAA compliance checks should be enabled
    input.config.hipaa_compliance_enabled == true
}

# Check if user has appropriate authentication level
user_authentication_level_check if {
    # User must be authenticated to access patient data
    input.metadata.user.authenticated == true

    # User type must be authorized for clinical data
    authorized_types := ["clinician", "doctor", "nurse", "administrator", "researcher"]
    user_type := input.metadata.user.type
    authorized_types[_] == user_type
}

# Rejection reasons
rejection_reasons = reasons if {
    reasons := array.concat(
        input_validation_rejection_reasons,
        patient_data_input_rejection_reasons
    )
}

# Input validation rejection reasons
input_validation_rejection_reasons = reasons if {
    not input_validation.allow
    reasons := input_validation.rejection_reasons
} else = [] if {
    true
}

# Patient data input specific rejection reasons
patient_data_input_rejection_reasons = array.concat(
    document_type_reasons,
    array.concat(
        prohibited_request_reasons,
        array.concat(
            config_reasons,
            array.concat(
                data_type_reasons,
                auth_reasons
            )
        )
    )
)

document_type_reasons = reasons if {
    not input.content_type == "input"
    reasons := [{"category": "Content Type", "reason": "Expected input document but received another type"}]
} else = [] if {
    true
}

prohibited_request_reasons = reasons if {
    contains_prohibited_patient_data_requests(input.content)
    reasons := [{"category": "Patient Data", "reason": "Input contains requests for direct patient data which may violate privacy regulations"}]
} else = [] if {
    true
}

config_reasons = reasons if {
    not phi_config_check
    reasons := [{"category": "Configuration", "reason": "PHI detection and HIPAA compliance must be enabled for patient data requests"}]
} else = [] if {
    true
}

data_type_reasons = array.concat(ssn_reasons, financial_reasons)

ssn_reasons = reasons if {
    contains_ssn_request(input.content)
    reasons := [{"category": "Sensitive Data", "reason": "Requests for SSNs or government IDs are not permitted"}]
} else = [] if {
    true
}

financial_reasons = reasons if {
    contains_financial_info_request(input.content)
    reasons := [{"category": "Sensitive Data", "reason": "Requests for financial information are not permitted"}]
} else = [] if {
    true
}

auth_reasons = reasons if {
    not user_authentication_level_check
    reasons := [{"category": "Authentication", "reason": "User does not have appropriate authentication level for patient data access"}]
} else = [] if {
    true
}

# Policy Metadata
policy_metadata = {
    "name": "Patient Data Protection Input Guardrail",
    "description": "Input validation guardrail for patient data protection in GenAI applications",
    "version": "1.1.0",
    "last_updated": "2023-07-15",
    "regulatory_references": [
        "EU AI Act",
        "NIST AI RMF",
        "HIPAA",
        "GDPR",
        "California CMIA",
        "Australian Privacy Act",
        "Health Records Act"
    ]
}

package tavoai.healthcare.guardrails.patient_data_protection_output

# Runtime guardrail for patient data protection output validation
# Based on EU AI Act, NIST AI RMF, HIPAA, GDPR and other privacy regulations
# Specific to healthcare industry

# Import common modules
import data.tavoai.common.output_filtering
import data.tavoai.common.data.patterns

# Default deny
default allow = false

# Allow patient data output if all checks pass
allow if {
    # Basic output validation checks
    output_filtering.allow

    # Verify this is an output document
    input.content_type == "output"

    # Healthcare-specific output checks
    patient_data_output_checks
}

# Core patient data output checks
patient_data_output_checks if {
    # Check if the output properly de-identifies patient data
    not contains_patient_identifiers(input.content)

    # Check if the output includes appropriate disclaimers
    contains_data_protection_disclaimers(input.content)

    # Check if the output is compliant with healthcare privacy laws
    privacy_compliance_check
}

# Helper function to detect patient identifiers
contains_patient_identifiers(text) if {
    patient_identifier_patterns := [
        "(?i)Patient\\s+(ID|Number|#):\\s*[A-Za-z0-9\\-]+",
        "(?i)MRN\\s*[#:]?\\s*[A-Za-z0-9\\-]+",
        "(?i)Record\\s+(ID|Number|#):\\s*[A-Za-z0-9\\-]+",
        "(?i)SSN\\s*[#:]?\\s*[\\d\\-]+",
        "(?i)(\\d{3}-\\d{2}-\\d{4})",  # SSN format
        "(?i)(\\d{3}-\\d{3}-\\d{4})",  # Phone number format
        "(?i)([A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,})",  # Email format
        "(?i)DOB\\s*[:]?\\s*\\d{1,2}[/-]\\d{1,2}[/-]\\d{2,4}"  # Date of birth
    ]

    pattern := patient_identifier_patterns[_]
    regex.match(pattern, text)
}

# Helper function to check for data protection disclaimers
contains_data_protection_disclaimers(text) if {
    disclaimer_patterns := [
        "(?i)(data|information).{1,30}(de-identified|anonymized)",
        "(?i)no.{1,20}(personal|identifiable).{1,20}information",
        "(?i)(compliant|compliance).{1,20}(with|to).{1,20}(HIPAA|privacy)",
        "(?i)(privacy|confidentiality).{1,20}protected"
    ]

    pattern := disclaimer_patterns[_]
    regex.match(pattern, text)
}

# Privacy compliance check
privacy_compliance_check if {
    # Get jurisdiction from metadata
    jurisdiction := input.metadata.jurisdiction

    # Apply jurisdiction-specific rules
    jurisdiction_specific_compliance(jurisdiction, input.content)
}

# US-specific compliance (HIPAA)
jurisdiction_specific_compliance("US", text) if {
    # HIPAA compliance - check for any PHI
    not contains_phi(text)
} else if {
    # If there is aggregate data, ensure it's properly de-identified
    contains_aggregate_data(text)
    contains_hipaa_safe_harbor_statement(text)
}

# EU-specific compliance (GDPR)
jurisdiction_specific_compliance("EU", text) if {
    # GDPR compliance
    not contains_personal_data(text)
} else if {
    # If there is personal data, ensure it's anonymized
    contains_personal_data(text)
    contains_gdpr_anonymization_statement(text)
}

# Australia-specific compliance
jurisdiction_specific_compliance("Australia", text) if {
    # Australian Privacy Act compliance
    not contains_personal_information(text)
} else if {
    # If there is personal information, ensure proper disclaimers
    contains_personal_information(text)
    contains_australian_privacy_statement(text)
}

# Default jurisdiction compliance (when not US, EU, or Australia)
jurisdiction_specific_compliance(jurisdiction, text) if {
    # Default privacy compliance check for other jurisdictions
    not contains_patient_identifiers(text)
}

# Helper functions for jurisdiction-specific compliance

# Check for PHI (Protected Health Information)
contains_phi(text) if {
    phi_patterns := [
        "(?i)name\\s*[:]\\s*[A-Za-z\\s\\.]+",
        "(?i)address\\s*[:]\\s*.+",
        "(?i)(medical|health)\\s+record\\s*[#:]\\s*[A-Za-z0-9\\-]+",
        "(?i)patient\\s+[A-Za-z0-9\\-]+"  # Patient followed by what could be an identifier
    ]

    pattern := phi_patterns[_]
    regex.match(pattern, text)
}

# Check for aggregate data
contains_aggregate_data(text) if {
    aggregate_patterns := [
        "(?i)(total|sum|count|average|mean|median)\\s+of\\s+patients",
        "(?i)(\\d+)\\s+patients",
        "(?i)patient\\s+population",
        "(?i)(statistical|aggregate|summary)\\s+(data|analysis|report)",
        "(?i)(percentage|proportion)\\s+of\\s+patients"
    ]

    pattern := aggregate_patterns[_]
    regex.match(pattern, text)
}

# Check for HIPAA Safe Harbor statement
contains_hipaa_safe_harbor_statement(text) if {
    regex.match("(?i)(compliant|compliance|accordance).{1,30}(with|to).{1,30}HIPAA.{1,30}(Safe Harbor|de-identification)", text)
}

# Check for personal data (GDPR context)
contains_personal_data(text) if {
    personal_data_patterns := [
        "(?i)individual\\s+patient",
        "(?i)specific\\s+person",
        "(?i)patient\\s+(named|identified\\s+as)",
        "(?i)patient's\\s+(information|data|details)"
    ]

    pattern := personal_data_patterns[_]
    regex.match(pattern, text)
}

# Check for GDPR anonymization statement
contains_gdpr_anonymization_statement(text) if {
    regex.match("(?i)(compliant|compliance|accordance).{1,30}(with|to).{1,30}(GDPR|EU).{1,30}(anonymization|data protection)", text)
}

# Check for personal information (Australian context)
contains_personal_information(text) if {
    # Similar to personal data patterns but with Australian context
    regex.match("(?i)(individual|specific).{1,20}(patient|person)", text)
}

# Check for Australian privacy statement
contains_australian_privacy_statement(text) if {
    regex.match("(?i)(compliant|compliance|accordance).{1,30}(with|to).{1,30}(Australian Privacy Act|Privacy Principles)", text)
}

# Rejection reasons
rejection_reasons = reasons if {
    reasons := array.concat(
        output_filtering_rejection_reasons,
        array.concat(
            document_type_reasons,
            array.concat(
                identifier_reasons,
                array.concat(
                    disclaimer_reasons,
                    privacy_reasons
                )
            )
        )
    )
}

# Output filtering rejection reasons
output_filtering_rejection_reasons = reasons if {
    not output_filtering.allow
    reasons := output_filtering.rejection_reasons
} else = [] if {
    true
}

